function parseMarkdownToSections(
  markdown: string
): { key: string; title: string; content: string }[] {
  const sections: { key: string; title: string; content: string }[] = []
  const lines = markdown.split("\n")
  let currentTitle = ""
  let currentContent: string[] = []

  for (const line of lines) {
    const h2Match = line.match(/^##\s+(.+)$/)
    const h1Match = line.match(/^#\s+(.+)$/)

    if (h2Match || h1Match) {
      if (currentTitle) {
        const key = currentTitle
          .toLowerCase()
          .normalize("NFD")
          .replace(/[\u0300-\u036f]/g, "")
          .replace(/[^a-z0-9]+/g, "-")
          .replace(/^-|-$/g, "")
        sections.push({ key, title: currentTitle, content: currentContent.join("\n").trim() })
      }
      currentTitle = (h2Match || h1Match)![1].trim()
      currentContent = []
    } else {
      currentContent.push(line)
    }
  }

  if (currentTitle) {
    const key = currentTitle
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-|-$/g, "")
    sections.push({ key, title: currentTitle, content: currentContent.join("\n").trim() })
  }

  return sections
}


export default function ProposalEditorPage({
  params,
}: {
  params: Promise<{ id: string }>
}) {
  const { id } = use(params)
  const router = useRouter()
  const {
    getProposal,
    addMessage,
    setProposalContent,
    updateProposal,
  } = useProposals()

  const { projects, addProject, addKnowledgeBaseFile } = useProjects()
  const { leads } = useLeads()

  const proposal = getProposal(id)

  useBreadcrumbSetter([
    { label: "Gerador de Proposta", href: "/dashboard/gerador-de-proposta" },
    { label: proposal?.nome ?? "Proposta" },
  ])

  const [isProcessing, setIsProcessing] = useState(false)
  const [highlightedSections, setHighlightedSections] = useState<Set<string>>(new Set())
  const [activeTab, setActiveTab] = useState<"chat" | "proposta">("chat")

  const empresa = proposal?.empresa ?? ""
  const para = proposal?.para ?? ""
  const projeto = proposal?.projeto ?? ""
  const interesse = proposal?.interesse ?? "Vazio"
  const modeloTrabalho = proposal?.modeloTrabalho ?? "Vazio"

  // Find linked lead
  const leadOrigem = proposal?.leadOrigemId
    ? leads.find((l) => l.id === proposal.leadOrigemId)
    : undefined

  const handleSendMessage = useCallback(
    async (content: string, fileName?: string) => {
      if (!proposal) return

      const userMsg: ProposalMessage = {
        id: `user-${Date.now()}`,
        role: "user",
        content,
        fileName,
      }
      addMessage(id, userMsg)
      setIsProcessing(true)

      const contextParts: string[] = []
      if (para) contextParts.push(`Cliente: ${para}`)
      if (empresa) contextParts.push(`Empresa: ${empresa}`)
      if (projeto) contextParts.push(`Projeto: ${projeto}`)
      if (interesse && interesse !== "Vazio") contextParts.push(`Interesse/Tipo: ${interesse}`)
      if (modeloTrabalho && modeloTrabalho !== "Vazio") contextParts.push(`Modelo: ${modeloTrabalho}`)
      const context = contextParts.join("\n")

      const apiMessages = [
        ...proposal.conversationHistory.map((m) => ({
          role: m.role,
          content: m.content,
        })),
        { role: "user" as const, content },
      ]

      try {
        const data = await callProposalGeneratorAction({ context, messages: apiMessages, lead_id: proposal.leadOrigemId })

        const aiContent = data.assistant_message || "Resposta recebida."
        const sections = parseMarkdownToSections(aiContent)

        if (data.is_proposal_ready && sections.length > 0) {
          setProposalContent(id, sections)
          const keys = sections.map((s) => s.key)
          setHighlightedSections(new Set(keys))
          setTimeout(() => setHighlightedSections(new Set()), 2000)
          setActiveTab("proposta")

          addMessage(id, {
            id: `ai-${Date.now()}`,
            role: "assistant",
            content: "✅ Proposta comercial gerada com sucesso! Confira o documento ao lado.",
          })
        } else {
          addMessage(id, {
            id: `ai-${Date.now()}`,
            role: "assistant",
            content: aiContent,
          })
        }
      } catch (error) {
        console.error("[proposal-generator] Error:", error)
        addMessage(id, {
          id: `ai-error-${Date.now()}`,
          role: "assistant",
          content: "Desculpe, ocorreu um erro ao processar sua mensagem. Tente novamente.",
        })
      } finally {
        setIsProcessing(false)
      }
    },
    [id, proposal, empresa, para, projeto, interesse, modeloTrabalho, addMessage, setProposalContent]
  )

  function handleMarkConcluida() {
    updateProposal(id, { status: "Concluída" })
    toast.success("Proposta marcada como concluída!")
  }

  function generateJiraKey(name: string): string {
    const words = name.split(/\s+/).filter(Boolean)
    let key = words.map((w) => w[0]?.toUpperCase()).join("")
    if (!key) key = "PRJ"
    const existingKeys = projects.map((p) => p.jiraKey)
    if (!existingKeys.includes(key)) return key
    let i = 2
    while (existingKeys.includes(`${key}${i}`)) i++
    return `${key}${i}`
  }

  function handleAprovar() {
    if (!proposal) return
    const jiraKey = generateJiraKey(empresa)
    const newProject = addProject({
      name: empresa,
      jiraKey,
      status: "Ativo",
      baseConhecimento: [],
    })
    const sanitizedName = empresa.replace(/\s+/g, "_")
    addKnowledgeBaseFile(newProject.id, {
      id: `kb-prop-${Date.now()}`,
      nome: `Proposta_Comercial_${sanitizedName}.pdf`,
      tipo: ".pdf",
      tamanho: "256 KB",
      dataUpload: Date.now(),
      enviadoPor: "João Silva",
      origem: "Proposta Comercial",
      conteudo: JSON.stringify(proposal.proposalContent),
    })
    updateProposal(id, {
      status: "Aprovada",
      projetoGeradoId: newProject.id,
    })
    toast.success(`Proposta aprovada com sucesso! O projeto "${empresa}" foi criado e a proposta adicionada a base de conhecimento.`)
  }

  if (!proposal) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <div className="text-center">
          <p className="text-sm text-muted-foreground">Proposta não encontrada.</p>
          <Button
            variant="link"
            onClick={() => router.push("/dashboard/gerador-de-proposta")}
            className="mt-2 text-primary"
          >
            Voltar para listagem
          </Button>
        </div>
      </div>
    )
  }

  const projetoGerado = proposal.projetoGeradoId
    ? projects.find((p) => p.id === proposal.projetoGeradoId)
    : undefined

  return (
    <div className="flex flex-1 flex-col gap-4 overflow-hidden">
      {/* Top bar with fields */}
      <div className="flex flex-col gap-3">
        {/* Row 1: Para + Empresa + Projeto */}
        <div className="grid grid-cols-1 gap-3 sm:grid-cols-3">
          <div>
            <Label htmlFor="editor-para" className="text-xs font-medium text-muted-foreground">
              Para (Nome do Cliente)
            </Label>
            <Input
              id="editor-para"
              value={para}
              onChange={(e) => updateProposal(id, { para: e.target.value })}
              placeholder="Nome do cliente"
              className="mt-1"
            />
          </div>
          <div>
            <Label htmlFor="editor-empresa" className="text-xs font-medium text-muted-foreground">
              Empresa
            </Label>
            <Input
              id="editor-empresa"
              value={empresa}
              onChange={(e) => updateProposal(id, { empresa: e.target.value })}
              placeholder="Nome da empresa"
              className="mt-1"
            />
          </div>
          <div>
            <Label htmlFor="editor-projeto" className="text-xs font-medium text-muted-foreground">
              Projeto
            </Label>
            <Input
              id="editor-projeto"
              value={projeto}
              onChange={(e) => updateProposal(id, { projeto: e.target.value })}
              placeholder="Nome do projeto"
              className="mt-1"
            />
          </div>
        </div>
        {/* Row 2: Interesse + Modelo */}
        <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
          <div>
            <Label className="text-xs font-medium text-muted-foreground">Interesse</Label>
            <Select
              value={interesse}
              onValueChange={(val) => updateProposal(id, { interesse: val as ProposalInteresse })}
            >
              <SelectTrigger className="mt-1">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {interesseOptions.map((opt) => (
                  <SelectItem key={opt} value={opt}>{opt === "Vazio" ? "Não definido" : opt}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          <div>
            <Label className="text-xs font-medium text-muted-foreground">Modelo de Trabalho</Label>
            <Select
              value={modeloTrabalho}
              onValueChange={(val) => updateProposal(id, { modeloTrabalho: val as ProposalModelo })}
            >
              <SelectTrigger className="mt-1">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {modeloOptions.map((opt) => (
                  <SelectItem key={opt} value={opt}>{opt === "Vazio" ? "Não definido" : opt}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>
      </div>

      {/* Lead link banner */}
      {leadOrigem && (
        <div className="flex items-center gap-3 rounded-lg bg-secondary px-4 py-3">
          <Target className="h-4 w-4 shrink-0 text-primary" />
          <p className="text-sm text-primary">
            {"Esta proposta foi gerada a partir do lead "}
            <strong>{`"${leadOrigem.titulo}"`}</strong>.{" "}
            <Link
              href="/dashboard/leads"
              className="font-medium underline underline-offset-2 hover:text-primary/90"
            >
              Ver Lead
            </Link>
          </p>
        </div>
      )}

      {/* Mobile tab switcher */}
      <div className="flex gap-1 rounded-lg bg-muted p-1 lg:hidden">
        <Button
          variant={activeTab === "chat" ? "secondary" : "ghost"}
          onClick={() => setActiveTab("chat")}
          className={`flex-1 rounded-md px-3 py-1.5 text-sm font-medium ${
            activeTab === "chat"
              ? "bg-card text-foreground shadow-sm"
              : "text-muted-foreground hover:text-foreground"
          }`}
        >
          Assistente
        </Button>
        <Button
          variant={activeTab === "proposta" ? "secondary" : "ghost"}
          onClick={() => setActiveTab("proposta")}
          className={`flex-1 rounded-md px-3 py-1.5 text-sm font-medium ${
            activeTab === "proposta"
              ? "bg-card text-foreground shadow-sm"
              : "text-muted-foreground hover:text-foreground"
          }`}
        >
          Proposta
        </Button>
      </div>

      {/* Desktop: 50/50 split */}
      <div className="flex flex-1 gap-4 overflow-hidden">
        <div
          className={`flex-1 overflow-hidden lg:flex lg:max-w-none ${
            activeTab === "chat" ? "flex" : "hidden lg:flex"
          }`}
          style={{ flex: "1 1 50%" }}
        >
          <div className="flex w-full flex-col overflow-hidden md:flex-[45] lg:flex-[50]">
            <ProposalChatPanel
              messages={proposal.conversationHistory}
              onSendMessage={handleSendMessage}
              isProcessing={isProcessing}
            />
          </div>
        </div>

        <div
          className={`flex-1 overflow-hidden lg:flex lg:max-w-none ${
            activeTab === "proposta" ? "flex" : "hidden lg:flex"
          }`}
          style={{ flex: "1 1 50%" }}
        >
          <div className="flex w-full flex-col overflow-hidden md:flex-[55] lg:flex-[50]">
            <ProposalDocument
              empresa={empresa}
              para={para}
              projeto={projeto}
              proposalNumber={proposal.proposalNumber}
              dataCriacao={proposal.dataCriacao}
              sections={proposal.proposalContent}
              highlightedSections={highlightedSections}
              status={proposal.status}
              interesse={interesse}
              modeloTrabalho={modeloTrabalho}
              projetoGeradoId={proposal.projetoGeradoId}
              projetoGeradoNome={projetoGerado?.name}
              onMarkConcluida={handleMarkConcluida}
              onAprovar={handleAprovar}
            />
          </div>
        </div>
      </div>

      {activeTab === "proposta" && proposal.proposalContent.length > 0 && (
        <div className="fixed bottom-4 left-1/2 z-30 -translate-x-1/2 lg:hidden">
          <Button
            className="bg-primary text-primary-foreground shadow-lg hover:bg-primary/90"
            size="default"
          >
            <Download className="mr-2 h-4 w-4" />
            Baixar PDF
          </Button>
        </div>
      )}
    </div>
  )
}

"use client"

import { useState, useRef } from "react"
import { Download, Loader2, FileText, CheckCircle, Check, Link2 } from "lucide-react"
import { toast } from "sonner"
import Link from "next/link"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { cn } from "@/lib/utils"
import { MarkdownRenderer } from "@/components/markdown-renderer"
import type { ProposalSection, ProposalStatus, ProposalInteresse, ProposalModelo } from "@/lib/proposal-types"
import { formatDateShort } from "@/lib/proposal-types"
import { buildProposalTokens } from "@/lib/proposal-pdf-utils"

interface ProposalDocumentProps {
  empresa: string
  para?: string
  projeto?: string
  proposalNumber: string
  dataCriacao: number
  sections: ProposalSection[]
  highlightedSections: Set<string>
  status: ProposalStatus
  interesse?: ProposalInteresse
  modeloTrabalho?: ProposalModelo
  projetoGeradoId?: string
  projetoGeradoNome?: string
  onMarkConcluida?: () => void
  onAprovar?: () => void
}

export function ProposalDocument({
  empresa,
  para,
  projeto,
  proposalNumber,
  dataCriacao,
  sections,
  highlightedSections,
  status,
  interesse,
  modeloTrabalho,
  projetoGeradoId,
  projetoGeradoNome,
  onMarkConcluida,
  onAprovar,
}: ProposalDocumentProps) {
  const [downloading, setDownloading] = useState(false)
  const [approveOpen, setApproveOpen] = useState(false)
  const documentRef = useRef<HTMLDivElement>(null)

  async function handleDownloadPDF() {
    if (sections.length === 0) return
    setDownloading(true)
    try {
      // 1. Busca o novo template dinâmico
      const res = await fetch("/proposta-template.html")
      if (!res.ok) throw new Error("Template não encontrado")
      let html = await res.text()

      // 2. Constrói os tokens com o novo sistema de mapeamento
      const tokens = buildProposalTokens({ empresa, para, projeto, modeloTrabalho, dataCriacao, sections })

      // 3. Substitui todas as variáveis no HTML
      for (const [key, value] of Object.entries(tokens)) {
        html = html.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value || '')
      }

      // 4. Remove variáveis não utilizadas (novo sistema de limpeza)
      html = html.replace(/\{\{[A-Z_]+\}\}/g, '')

      // 5. Abre em nova janela e dispara impressão automaticamente
      const win = window.open("", "_blank")
      if (!win) {
        toast.error("Pop-up bloqueado. Permita pop-ups para este site e tente novamente.")
        return
      }
      win.document.open()
      win.document.write(html)
      win.document.close()

      // Aguarda carregamento completo antes de imprimir
      win.addEventListener("load", () => win.print())
      setTimeout(() => { if (win && !win.closed) win.print() }, 800)

      toast.success("Proposta aberta! Selecione 'Salvar como PDF' com margens 'Nenhuma'.")
    } catch (err) {
      console.error("[ProposalDocument] PDF error:", err)
      toast.error("Erro ao gerar o PDF.")
    } finally {
      setDownloading(false)
    }
  }

  function getStatusBadge() {
    switch (status) {
      case "Aprovada":
        return <Badge variant="default">Aprovada</Badge>
      case "Concluída":
        return <Badge variant="secondary" className="bg-green-100 text-green-700 hover:bg-green-100">Concluída</Badge>
      case "Rascunho":
      default:
        return <Badge variant="outline" className="bg-yellow-50 text-yellow-700 hover:bg-yellow-50">Rascunho</Badge>
    }
  }

  return (
    <div className="flex h-full flex-col rounded-lg border border-border bg-card shadow-sm">
      {/* Header */}
      <div className="flex flex-wrap items-center justify-between gap-2 border-b border-border px-4 py-3">
        <div className="flex items-center gap-2">
          <h2 className="text-sm font-semibold text-foreground">Proposta Comercial</h2>
          {sections.length > 0 && getStatusBadge()}
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <Button
            variant="outline"
            size="sm"
            onClick={handleDownloadPDF}
            disabled={downloading || sections.length === 0}
            className="text-primary border-primary/30 hover:bg-secondary"
          >
            {downloading ? (
              <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
            ) : (
              <Download className="mr-1.5 h-3.5 w-3.5" />
            )}
            Imprimir / Salvar PDF
          </Button>
          {/* Mark as Concluida - visible when Rascunho and has content */}
          {status === "Rascunho" && sections.length > 0 && onMarkConcluida && (
            <Button
              variant="outline"
              size="sm"
              onClick={onMarkConcluida}
              className="border-[#16a34a]/30 text-[#16a34a] hover:bg-[#dcfce7]"
            >
              <CheckCircle className="mr-1.5 h-3.5 w-3.5" />
              Marcar como Concluída
            </Button>
          )}
          {/* Aprovar Proposta - visible when Concluída */}
          {status === "Concluída" && onAprovar && (
            <Button
              size="sm"
              onClick={() => setApproveOpen(true)}
              className="bg-[#16a34a] text-primary-foreground hover:bg-[#15803d]"
            >
              <CheckCircle className="mr-1.5 h-3.5 w-3.5" />
              Aprovar Proposta
            </Button>
          )}
        </div>
      </div>

      {/* Approved info banner */}
      {status === "Aprovada" && projetoGeradoId && (
        <div className="flex items-center gap-3 border-b border-border bg-secondary px-4 py-3">
          <Link2 className="h-4 w-4 shrink-0 text-primary" />
          <p className="text-sm text-primary">
            {"Esta proposta foi aprovada e gerou o projeto "}
            <strong>{`"${projetoGeradoNome || ""}"`}</strong>.{" "}
            <Link href={`/dashboard/projetos/${projetoGeradoId}`} className="font-medium underline underline-offset-2 hover:text-primary/90">
              Ver Projeto
            </Link>
          </p>
        </div>
      )}

      {/* Document content */}
      <div ref={documentRef} className="flex-1 overflow-y-auto p-4 lg:p-6">
        {sections.length === 0 ? (
          <div className="flex h-full flex-col items-center justify-center rounded-lg border-2 border-dashed border-border p-6 text-center">
            <FileText className="mb-3 h-12 w-12 text-muted-foreground/40" />
            <p className="text-sm font-medium text-muted-foreground">
              A proposta sera gerada aqui conforme voce fornecer informacoes ao assistente.
            </p>
            <p className="mt-1 text-xs text-muted-foreground">
              Comece a conversa ao lado!
            </p>
          </div>
        ) : (
          <div className="mx-auto max-w-[700px] rounded-lg border border-border bg-card p-4 shadow-md lg:p-8">
            {/* Document Header */}
            <div className="mb-6 border-b border-border pb-6">
              <div className="mb-4 text-center">
                <h1 className="text-base font-extrabold uppercase tracking-widest text-primary lg:text-lg">
                  PROPOSTA COMERCIAL — PROJETO SOB MEDIDA
                </h1>
                {modeloTrabalho && modeloTrabalho !== "Vazio" && (
                  <p className="mt-1.5 text-[11px] font-semibold uppercase tracking-widest text-primary/70">
                    MODELO DE CONTRATAÇÃO: {modeloTrabalho.toUpperCase()}
                  </p>
                )}
              </div>
              <div className="mx-auto mb-4 h-px w-16 bg-primary/30" />
              <div className="grid grid-cols-2 gap-x-6 gap-y-1.5">
                {[
                  ["PARA", para || "—"],
                  ["EMPRESA", empresa || "—"],
                  ["PROJETO", projeto || "—"],
                  ["DATA", formatDateShort(dataCriacao)],
                  ["VALIDADE", "30 dias"],
                  ["PROPOSTA Nº", `WA-${proposalNumber}`],
                ].map(([label, value]) => (
                  <div key={label} className="flex gap-1.5 text-xs lg:text-sm">
                    <span className="min-w-[90px] shrink-0 font-bold text-foreground">{label}:</span>
                    <span className="text-foreground/70">{value}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Sections */}
            <div className="flex flex-col gap-6">
              {sections.map((section) => (
                <div
                  key={section.key}
                  className={cn(
                    "rounded-md px-3 py-2 transition-colors",
                    highlightedSections.has(section.key) && "section-highlight"
                  )}
                >
                  <h2 className="mb-3 border-b border-border/60 pb-1.5 text-sm font-bold text-primary lg:text-base">
                    {section.title}
                  </h2>
                  <MarkdownRenderer
                    content={section.content
                      .split("\n")
                      .filter((l) => {
                        const t = l.trim()
                        if (/^-{1,3}$/.test(t)) return false
                        if (/^[-*•✅❌]?\s*(PARA|EMPRESA|DATA|VALIDADE|TIPO|MODELO|PROPOSTA\s*N[ºo°]?):/i.test(t)) return false
                        return true
                      })
                      .join("\n")}
                    className="prose-h3:text-primary prose-h3:font-semibold prose-h4:text-foreground/90"
                  />
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Approve confirmation dialog */}
      <AlertDialog open={approveOpen} onOpenChange={setApproveOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <div className="mb-2 flex justify-center">
              <div className="flex h-12 w-12 items-center justify-center rounded-full bg-[#dcfce7]">
                <CheckCircle className="h-6 w-6 text-[#16a34a]" />
              </div>
            </div>
            <AlertDialogTitle className="text-center">Aprovar Proposta</AlertDialogTitle>
            <AlertDialogDescription className="text-center">
              Ao aprovar esta proposta, as seguintes acoes serao realizadas automaticamente:
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="flex flex-col gap-2 rounded-lg bg-secondary/50 p-4">
            <div className="flex items-start gap-2">
              <Check className="mt-0.5 h-4 w-4 shrink-0 text-[#16a34a]" />
              <span className="text-sm text-foreground">
                {`Um novo projeto sera criado com o nome "${empresa}"`}
              </span>
            </div>
            <div className="flex items-start gap-2">
              <Check className="mt-0.5 h-4 w-4 shrink-0 text-[#16a34a]" />
              <span className="text-sm text-foreground">
                A proposta comercial sera adicionada a base de conhecimento do novo projeto
              </span>
            </div>
            <div className="flex items-start gap-2">
              <Check className="mt-0.5 h-4 w-4 shrink-0 text-[#16a34a]" />
              <span className="text-sm text-foreground">
                {`O status da proposta sera alterado para "Aprovada"`}
              </span>
            </div>
          </div>
          <p className="text-center text-xs text-muted-foreground">Deseja prosseguir?</p>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => {
                setApproveOpen(false)
                onAprovar?.()
              }}
              className="bg-[#16a34a] text-primary-foreground hover:bg-[#15803d]"
            >
              Aprovar
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  )
}

import type { ProposalSection, ProposalModelo } from "@/lib/proposal-types"
import { formatDateShort } from "@/lib/proposal-types"

export function clean(text: string): string {
  return text.replace(/\*\*/g, "").replace(/\*/g, "").trim()
}

export function findSection(sections: ProposalSection[], ...keywords: string[]): ProposalSection | undefined {
  return sections.find((s) =>
    keywords.some((k) => s.key.toLowerCase().includes(k) || s.title.toLowerCase().includes(k))
  )
}

// ── GERAÇÃO DE HTML ESTRUTURADO ──

export function gerarFuncionalidadesHTML(content: string): string {
  const lines = content.split("\n")
  const items: string[] = []

  for (const line of lines) {
    const t = line.trim()
    // Formato: "1. **Nome** — Descrição"
    const m1 = t.match(/^(\d+)\.\s+\*\*(.+?)\*\*\s*[—–:\-]\s*(.+)$/)
    if (m1) {
      items.push(`<div class="func-item"><p><strong>${m1[1]}. ${m1[2]}</strong> - ${clean(m1[3])}</p></div>`)
      continue
    }

    // Formato: "1. Nome — Descrição"
    const m2 = t.match(/^(\d+)\.\s+(.+?)\s*[—–]\s*(.+)$/)
    if (m2) {
      items.push(`<div class="func-item"><p><strong>${m2[1]}. ${m2[2]}</strong> - ${clean(m2[3])}</p></div>`)
      continue
    }

    // Formato: "- **Nome**: Descrição"
    const m3 = t.match(/^[-*•]\s+\*\*(.+?)\*\*[:\s]+(.+)$/)
    if (m3) {
      items.push(`<div class="func-item"><p><strong>${items.length + 1}. ${m3[1]}</strong> - ${clean(m3[2])}</p></div>`)
      continue
    }
  }

  // Fallback: itens simples com bullet points
  if (!items.length) {
    content.split("\n")
      .filter((l) => /^[-*•]\s/.test(l.trim()))
      .slice(0, 8)
      .forEach((l, i) => {
        items.push(`<div class="func-item"><p><strong>${i + 1}. ${clean(l.replace(/^[-*•]\s+/, ""))}</strong></p></div>`)
      })
  }

  return items.join("\n\n")
}

export function gerarFasesHTML(content: string): string {
  const lines = content.split("\n")
  const phases: string[] = []
  let counter = 0

  for (const line of lines) {
    const t = line.trim()
    if (!t) continue

    // Formato: "Fase 1 - Nome | Prazo"
    const m1 = t.match(/^(?:Fase\s*)?(\d+)\s*[-:]\s*(.+?)\s*\|\s*(.+)$/)
    if (m1) {
      phases.push(`<div class="phase"><strong>Fase ${m1[1]}:</strong> ${clean(m1[2])} – ${clean(m1[3])}</div>`)
      continue
    }

    // Formato: "Fase 1 - Nome"
    const m2 = t.match(/^Fase\s*(\d+)\s*[-:]\s*(.+)$/)
    if (m2) {
      phases.push(`<div class="phase"><strong>Fase ${m2[1]}:</strong> ${clean(m2[2])}</div>`)
      continue
    }

    // Bullets com prazo
    if (/^[-*•]\s/.test(t) && /semana|mês|mes|dias?/i.test(t)) {
      counter++
      phases.push(`<div class="phase"><strong>Fase ${counter}:</strong> ${clean(t.replace(/^[-*•]\s+/, ""))}</div>`)
    }
  }

  return phases.join("\n") || `<div class="phase"><strong>Fase 1:</strong> A definir</div>`
}

export function gerarEntregaveisHTML(content: string): string {
  const deliverableKeywords = /protótipo|figma|documentação|código|repositório|sistema|produção|api\s|deploy|fonte/i
  const items = content
    .split("\n")
    .filter((l) => /^[-*•]\s/.test(l.trim()) && deliverableKeywords.test(l))
    .map((l) => `<li>${clean(l.replace(/^[-*•]\s+/, ""))}</li>`)

  if (items.length) {
    return `<ul>\n${items.join("\n")}\n</ul>`
  }

  // Lista padrão de entregáveis
  return `<ul>
<li>Protótipos de Alta Fidelidade (Figma).</li>
<li>Documentação Funcional.</li>
<li>Documentação Técnica.</li>
<li>Código Fonte Completo (repositório Git).</li>
<li>Sistema em Produção.</li>
</ul>`
}

export function gerarServicosHTML(): string {
  return `<h3>Nossos serviços:</h3>
<ul>
<li>Desenvolvimento de Software.</li>
<li>Desenvolvimento de Aplicativos.</li>
<li>Soluções de Inteligência Artificial.</li>
<li>Alocação de Profissionais.</li>
</ul>`
}

export function gerarListaClientesHTML(): string {
  return `<ul>
<li>Easy Salon - Sistema de gestão para salões de beleza</li>
<li>Parceiros diversos em soluções de software sob medida</li>
<li>Consulte nossa carteira completa de projetos entregues</li>
</ul>`
}

export function gerarCondicoesPagamentoHTML(content: string): string {
  const vals = content.match(/R\$\s*[\d.,]+/g) ?? []
  const pct = content.match(/(\d+)%/g) ?? []

  const p1 = content.match(/(?:1[aª°]?\s*parcela|assinatura)[^R\n]*R\$\s*([\d.,]+)/i)
  const p2 = content.match(/(?:2[aª°]?\s*parcela)[^R\n]*R\$\s*([\d.,]+)/i)
  const p3 = content.match(/(?:3[aª°]?\s*parcela)[^R\n]*R\$\s*([\d.,]+)/i)

  const cond2m = content.match(/(\d+\s*dias?(?:\s*após[^,\n]+)?)/i)
  const cond3m = content.match(/(?:pós.homolog|entrega final|conclusão|go.live)/i)

  const parcela1 = p1 ? `R$ ${p1[1]}` : vals[0] ?? "A definir"
  const condicao2 = cond2m ? cond2m[1] : pct[1] ? `${pct[1]} na entrega parcial` : "30 dias após a assinatura"
  const parcela2 = p2 ? `R$ ${p2[1]}` : vals[1] ?? "A definir"
  const condicao3 = cond3m ? cond3m[0] : pct[2] ? `${pct[2]} na entrega final` : "Pós-homologação"
  const parcela3 = p3 ? `R$ ${p3[1]}` : vals[2] ?? "A definir"

  return `<div class="payment-condition"><strong>1ª parcela:</strong> ${parcela1} na assinatura do contrato</div>
<div class="payment-condition"><strong>2ª parcela:</strong> ${parcela2} - ${condicao2}</div>
<div class="payment-condition"><strong>3ª parcela:</strong> ${parcela3} - ${condicao3}</div>`
}

// ── FUNÇÕES DE EXTRAÇÃO (adaptadas para novo template) ──

export function extractValorTotal(content: string): string {
  const totalLine = content.split("\n").find((l) => /total/i.test(l) && /R\$/i.test(l))
  if (totalLine) {
    const m = totalLine.match(/R\$\s*[\d.,]+/)
    if (m) return `<p class="investment-total">Investimento total: ${m[0]}</p>`
  }
  const m = content.match(/R\$\s*[\d.,]+/)
  return m ? `<p class="investment-total">Investimento total: ${m[0]}</p>` : `<p class="investment-total">Investimento total: A definir</p>`
}

export function extractSubtitulo(content: string, projeto: string): string {
  if (projeto) return projeto
  const h3 = content.match(/^###\s+(.+)$/m)
  if (h3) return clean(h3[1])
  const bold = content.match(/\*\*(.+?)\*\*/)
  if (bold) return bold[1]
  return clean(content.split("\n").find((l) => l.trim()) ?? "Projeto")
}

export function extractDescricao(content: string): string {
  const lines = content.split("\n")
  const paragrafos = lines.filter((l) => {
    const t = l.trim()
    return t && !t.startsWith("#") && !t.startsWith("-") && !t.startsWith("*") && !/^\d+\./.test(t)
  }).map(l => `<p>${clean(l)}</p>`)

  return paragrafos.length > 0 ? paragrafos.join("\n") : "<p>Descrição do projeto.</p>"
}

export function extractPrazoTotal(content: string): string {
  const m1 = content.match(/(?:prazo|total|estimado)[:\s]+(\d+(?:[,.]\d+)?\s*(?:semanas?|meses?|dias?))/i)
  if (m1) return `<p><strong>Prazo total:</strong> ${m1[1]}</p>`
  const m2 = content.match(/(\d+(?:[,.]\d+)?\s*(?:semanas?|meses?))/i)
  if (m2) return `<p><strong>Prazo total:</strong> ${m2[1]}</p>`
  return "<p><strong>Prazo total:</strong> A definir</p>"
}

// ── FUNÇÃO PRINCIPAL DE MAPEAMENTO ──

export function buildProposalTokens(params: {
  empresa: string
  para: string | undefined
  projeto: string | undefined
  modeloTrabalho: ProposalModelo | undefined
  dataCriacao: number
  sections: ProposalSection[]
}): Record<string, string> {
  const { empresa, para, projeto, modeloTrabalho, dataCriacao, sections } = params

  // Buscar seções relevantes
  const sobreSection     = findSection(sections, "sobre", "objetivo", "projeto", "descricao")
  const escopoSection    = findSection(sections, "escopo", "funcionalidade", "requisito", "solucao")
  const cronoSection     = findSection(sections, "cronograma", "timeline", "prazo", "fase")
  const investSection    = findSection(sections, "investimento", "valor", "preco", "precificacao")
  const condicoesSection = findSection(sections, "condicao", "pagamento", "comercial", "financeiro")
  const entregaSection   = findSection(sections, "entregavel", "entrega", "deliverable")

  const sobreContent  = sobreSection?.content ?? ""
  const escopoContent = escopoSection?.content ?? sobreContent
  const cronoContent  = cronoSection?.content ?? ""
  const investContent = investSection?.content ?? ""
  const condicoesContent = condicoesSection?.content ?? investContent
  const entregaContent = entregaSection?.content ?? escopoContent

  // Mapear para as novas variáveis do template dinâmico
  return {
    // ── INFORMAÇÕES DA CAPA ──
    "NOME_CLIENTE": empresa || "—",
    "NOME_EMPRESA": "Wa Project",
    "TITULO_PROPOSTA": "Proposta Comercial",
    "DATA_PROPOSTA": formatDateShort(dataCriacao),
    "DIAS_VALIDADE": "30",
    "CLIENTE_EMPRESA": para || empresa || "—",
    "TIPO_ESCOPO": modeloTrabalho && modeloTrabalho !== "Vazio" ? modeloTrabalho : "Escopo Fechado",
    "INFORMACOES_ADICIONAIS_CAPA": "",
    "CONTEUDO_INICIAL_CAPA": "",

    // ── CONTEÚDO PRINCIPAL ──
    "TITULO_SOBRE_EMPRESA": "Sobre a Wa Project",
    "DESCRICAO_EMPRESA": "A Wa Project é uma software house especializada no desenvolvimento de soluções digitais inovadoras e sob medida. Com foco em qualidade e excelência técnica, entregamos projetos que transformam ideias em realidade digital.",
    "SECAO_SERVICOS": gerarServicosHTML(),
    "TITULO_CLIENTES": "Nossos Clientes",
    "LISTA_CLIENTES": gerarListaClientesHTML(),
    "INFORMACOES_ADICIONAIS_EMPRESA": "",

    // ── PROJETO E FUNCIONALIDADES ──
    "TITULO_PROJETO": "Sobre o Projeto",
    "SUBTITULO_PROJETO": extractSubtitulo(sobreContent, projeto ?? ""),
    "DESCRICAO_PROJETO": extractDescricao(sobreContent),
    "TITULO_FUNCIONALIDADES": "Funcionalidades",
    "LISTA_FUNCIONALIDADES": gerarFuncionalidadesHTML(escopoContent || sobreContent),
    "FUNCIONALIDADES_ADICIONAIS": "",

    // ── INTEGRAÇÕES ──
    "TITULO_INTEGRACOES": "Integrações",
    "DESCRICAO_INTEGRACOES": "<p>As integrações necessárias serão implementadas conforme especificações técnicas do projeto.</p>",

    // ── MODELO DE TRABALHO ──
    "TITULO_MODELO_TRABALHO": "Modelo de Trabalho",
    "DESCRICAO_MODELO": `<p>Utilizamos metodologia ágil com entregas incrementais, garantindo transparência e qualidade em cada etapa do desenvolvimento.</p>`,
    "TITULO_FASES": "Fases do Projeto",
    "LISTA_FASES": gerarFasesHTML(cronoContent),

    // ── EQUIPE ──
    "TITULO_EQUIPE": "Equipe",
    "DESCRICAO_EQUIPE": `<p>Nossa equipe é composta por profissionais experientes em desenvolvimento de software, design e gestão de projetos.</p>`,
    "LISTA_MEMBROS_EQUIPE": `<div class="team-role">
<h4>Tech Lead</h4>
<p>Responsável pela arquitetura técnica e liderança do desenvolvimento.</p>
</div>
<div class="team-role">
<h4>Desenvolvedor(es)</h4>
<p>Desenvolvimento front-end e back-end da solução.</p>
</div>
<div class="team-role">
<h4>Designer UX/UI</h4>
<p>Criação da interface e experiência do usuário.</p>
</div>`,

    // ── CRONOGRAMA ──
    "TITULO_CRONOGRAMA": "Cronograma",
    "PRAZO_TOTAL": extractPrazoTotal(cronoContent),
    "CRONOGRAMA_DETALHADO": "",
    "OBSERVACOES_CRONOGRAMA": "",

    // ── INVESTIMENTO ──
    "TITULO_INVESTIMENTO": "Investimento",
    "VALOR_TOTAL": extractValorTotal(investContent),
    "TITULO_CONDICOES_PAGAMENTO": "Condições de Pagamento",
    "CONDICOES_PAGAMENTO": gerarCondicoesPagamentoHTML(condicoesContent),

    // ── ENTREGÁVEIS ──
    "TITULO_ENTREGAVEIS": "Entregáveis",
    "LISTA_ENTREGAVEIS": gerarEntregaveisHTML(entregaContent),

    // ── PRÓXIMOS PASSOS ──
    "TITULO_PROXIMOS_PASSOS": "Próximos Passos",
    "LISTA_PROXIMOS_PASSOS": `<ul>
<li>Aprovação da proposta comercial</li>
<li>Assinatura do contrato</li>
<li>Kick-off do projeto</li>
<li>Início do desenvolvimento</li>
</ul>`,
    "MENSAGEM_FINAL_PASSOS": "",

    // ── ENCERRAMENTO ──
    "CITACAO_ENCERRAMENTO": `<p class="closing-quote">Estamos prontos para transformar sua visão em realidade digital!</p>`,
    "INFORMACOES_EMPRESA_COMPLETA": `<p><strong>SAKAMOTO TECNOLOGIA LTDA (Wa Project)</strong></p>
<p>CNPJ: 63.201.595/0001-63</p>
<p>Endereço: Al. Rio Negro, 503, Sala 2020, Alphaville, Barueri/SP</p>
<p>Site: https://www.severino.ninja</p>`,
    "TEXTO_VALIDADE": `<p>Esta proposta tem validade de 30 dias a partir da data de emissão.</p>`
  }
}

