597	// Sistema de paginação CSS aprimorado
598	document.addEventListener('DOMContentLoaded', function() {
599	    // Força atualização dos números de página via CSS counter
600	    function initializePagination() {
601	        // Reaplica counter-reset no body
602	        document.body.style.counterReset = 'page';
603	
604	        // Força re-render dos elementos de página
605	        const pageElements = document.querySelectorAll('.pg-num');
606	        pageElements.forEach(el => {
607	            el.style.counterIncrement = 'page';
608	            el.textContent = '';
609	            el.setAttribute('data-content', 'counter(page)');
610	        });
611	    }
612	
613	    // Detecta modo de impressão para comportamento específico
614	    window.addEventListener('beforeprint', function() {
615	        // CSS counter funciona melhor em modo de impressão
616	        setTimeout(initializePagination, 50);
617	    });
618	
619	    // Inicializa imediatamente
620	    initializePagination();
621	});
622	
623	// Sistema CSS de paginação com counter
624	function setupCSSCounters() {
625	    const style = document.createElement('style');
626	    style.textContent = `
627	        body { counter-reset: page; }
628	        .pg-num::after {
629	            content: counter(page);
630	            counter-increment: page;
631	        }
632	    `;
633	    document.head.appendChild(style);
634	}
635	
636	setupCSSCounters();
637	</script>
